// Script CORRIGIDO para extrair dados de produtos do HTML da Kalunga
// Agora com o link correto para a página de detalhes do produto

const htmlContent = $input.item.json.data || $input.item.json;

function extractProductData(html) {
    const products = [];

    // Encontrar cada bloco de produto
    const productBlocks = html.match(/<div class="blocoproduto[^"]*"[^>]*>[\s\S]*?<\/div>\s*<\/div>\s*<\/div>\s*<\/div>/g) || [];

    if (productBlocks.length === 0) {
        const altBlocks = html.match(/<div class="blocoproduto[^"]*"[^>]*>[\s\S]*?<\/div>\s*<\/div>\s*<\/div>/g) || [];
        if (altBlocks.length > 0) {
            return extractFromBlocks(altBlocks);
        }
        return [];
    }

    return extractFromBlocks(productBlocks);
}

function extractFromBlocks(blocks) {
    const products = [];

    for (const block of blocks) {
        try {
            const product = {};

            // 1. LINK CORRETO DA PÁGINA DO PRODUTO
            // Extrai o href do link que envolve a imagem ou título
            let productUrl = null;

            // Primeiro tenta encontrar o link principal (geralmente envolve a imagem)
            const linkMatches = block.match(/<a[^>]*href="([^"]*)"[^>]*class="blocoproduto__link[^"]*"[^>]*>/g);
            if (linkMatches) {
                for (const linkMatch of linkMatches) {
                    const hrefMatch = linkMatch.match(/href="([^"]*)"/);
                    if (hrefMatch) {
                        const href = hrefMatch[1];
                        // Pega o primeiro link que não seja vazio e contenha "/prod/"
                        if (href && href.includes('/prod/')) {
                            productUrl = href;
                            break;
                        }
                    }
                }
            }

            // Se não encontrou, tenta um padrão alternativo
            if (!productUrl) {
                const simpleLink = block.match(/href="(\/prod\/[^"]*)"/);
                if (simpleLink) {
                    productUrl = simpleLink[1];
                }
            }

            if (productUrl) {
                product.product_page_url = `https://www.kalunga.com.br${productUrl}`;
                product.link = product.product_page_url;
            }

            // 2. SKU e URL para adicionar ao carrinho
            const buyButtonMatch = block.match(/<button[^>]*onclick="ComprarComGarantia\('([^']*)'/);
            if (buyButtonMatch) {
                const sku = buyButtonMatch[1];
                product.sku = sku;
                product.add_to_cart_url = `https://www.kalunga.com.br/carrinho/adicionar/${sku}`;
                product.buy_button_action = `ComprarComGarantia('${sku}')`;
            } else {
                // Tenta extrair SKU da URL do produto
                if (productUrl) {
                    const skuFromUrl = productUrl.match(/\/([0-9]+)$/);
                    if (skuFromUrl) {
                        product.sku = skuFromUrl[1];
                        product.add_to_cart_url = `https://www.kalunga.com.br/carrinho/adicionar/${skuFromUrl[1]}`;
                    }
                }
            }

            // 3. Título/Descrição
            const titleMatch = block.match(/<h2[^>]*class="blocoproduto__title[^"]*"[^>]*>([^<]*)<\/h2>/);
            if (titleMatch) {
                product.title = titleMatch[1].trim();
            } else {
                const altTitle = block.match(/<a[^>]*class="blocoproduto__link[^"]*"[^>]*>[\s\S]*?<h2[^>]*>([^<]*)<\/h2>/);
                if (altTitle) {
                    product.title = altTitle[1].trim();
                }
            }

            // 4. IMAGEM
            const imgMatch = block.match(/<img[^>]*src="([^"]*)"[^>]*class="blocoproduto__image[^"]*"[^>]*>/);
            if (imgMatch) {
                product.image = imgMatch[1];
            } else {
                const sourceMatch = block.match(/<source[^>]*data-srcset="([^"]*)"[^>]*>/);
                if (sourceMatch) {
                    product.image = sourceMatch[1];
                } else {
                    const dataSrcMatch = block.match(/<img[^>]*data-src="([^"]*)"[^>]*>/);
                    if (dataSrcMatch) {
                        product.image = dataSrcMatch[1];
                    }
                }
            }

            // 5. PREÇO À VISTA
            const priceMatch = block.match(/<span[^>]*class="blocoproduto__text[^"]*blocoproduto__price[^"]*"[^>]*>[\s\S]*?R\$ ([0-9.,]+)/);
            if (priceMatch) {
                product.price_cash = parseFloat(priceMatch[1].replace(/\./g, '').replace(',', '.'));
                product.price_cash_formatted = `R$ ${priceMatch[1]}`;
            }

            // 6. PREÇO PARCELADO
            const installmentMatch = block.match(/<p[^>]*class="blocoproduto__text--bold blocoproduto__text--small mb-0"[^>]*>([0-9]+)x de R\$ ([0-9.,]+)/);
            if (installmentMatch) {
                product.installments = {
                    times: parseInt(installmentMatch[1]),
                    value: parseFloat(installmentMatch[2].replace(/\./g, '').replace(',', '.')),
                    formatted: `${installmentMatch[1]}x de R$ ${installmentMatch[2]}`
                };
            }

            // 7. PREÇO TOTAL A PRAZO
            const totalMatch = block.match(/Total a prazo: R\$ ([0-9.,]+)/);
            if (totalMatch) {
                product.price_total = parseFloat(totalMatch[1].replace(/\./g, '').replace(',', '.'));
                product.price_total_formatted = `R$ ${totalMatch[1]}`;
            }

            // 8. FRETE GRÁTIS
            const freightMatch = block.match(/<div[^>]*class="seloslot[^"]*"[^>]*>[\s\S]*?FRETE GRÁTIS/);
            if (freightMatch) {
                product.free_shipping = true;

                const regions = [];
                const regionItems = block.match(/<li[^>]*id="([^"]*)"[^>]*>([^<]*)<\/li>/g);
                if (regionItems) {
                    for (const item of regionItems) {
                        const regionMatch = item.match(/<li[^>]*id="([^"]*)"[^>]*>([^<]*)<\/li>/);
                        if (regionMatch) {
                            regions.push({
                                id: regionMatch[1],
                                name: regionMatch[2]
                            });
                        }
                    }
                }
                product.free_shipping_regions = regions;
                product.free_shipping_info = regions.map(r => r.name).join(', ');
            } else {
                product.free_shipping = false;
                product.free_shipping_regions = [];
                product.free_shipping_info = '';
            }

            // 9. AVALIAÇÃO
            const starsMatch = block.match(/<i[^>]*class="reviews__star_icon fa fa-star(?: text-warning)?"[^>]*><\/i>/g);
            if (starsMatch) {
                const activeStars = starsMatch.filter(s => s.includes('text-warning')).length;
                product.rating = activeStars;
                product.rating_max = 5;
            }

            // 10. NÚMERO DE AVALIAÇÕES
            const reviewsMatch = block.match(/<span[^>]*class="reviews__star_text[^"]*"[^>]*>\(([0-9]+)\)/);
            if (reviewsMatch) {
                product.reviews_count = parseInt(reviewsMatch[1]);
            }

            // Adicionar apenas se tiver pelo menos título
            if (product.title) {
                products.push(product);
            }

        } catch (error) {
            console.log('Erro ao extrair bloco:', error);
        }
    }

    return products;
}

const extractedProducts = extractProductData(htmlContent);

// Montar resultado
const result = {
    products: extractedProducts,
    total_products_found: extractedProducts.length,
    search_term: htmlContent.match(/<input[^>]*id="termoBuscado"[^>]*value="([^"]*)"[^>]*>/)?.[1] || 'Não identificado',
    extracted_at: new Date().toISOString()
};

return [{ json: result }];
